package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }
import ssg.js.compress.ToplevelConfig

final class CompressClassPropertiesSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // class_expression_properties_side_effects
  // =========================================================================
  test("class_expression_properties_side_effects".fail) {
    assertCompresses(
      input = """global.side = () => { console.log("PASS") };
        (class {
            static foo = side();
            [side()]() {};
            [side()] = 4
        })""".stripMargin.trim,
      expected = """global.side = () => { console.log("PASS") };
        side(),side(),side()""".stripMargin.trim,
      options = AllOff.copy(
        sideEffects = true,
        unused = true
      )
    )
  }

  // =========================================================================
  // class_expression_not_constant
  // =========================================================================
  test("class_expression_not_constant".fail) {
    assertCompresses(
      input = """const obj = {};
        leak();
        obj.Class1 = class { static foo = leak() };
        obj.Class2 = class extends Obj.Class1 {};
        new obj.Class2()""".stripMargin.trim,
      expected = """const obj = {} // Class1 not inlined into object
        leak();
        obj.Class1 = class { static foo = leak() };
        obj.Class2 = class extends Obj.Class1 {};
        new obj.Class2""".stripMargin.trim,
      options = AllOff.copy(
        collapseVars = true,
        joinVars = true,
        properties = true,
        reduceVars = true,
        sideEffects = true,
        unused = true
      )
    )
  }

  // =========================================================================
  // class_expression_constant
  // =========================================================================
  test("class_expression_constant".fail) {
    assertCompresses(
      input = """const obj = {};
        obj.Class1 = class { static foo = "constant" };
        obj.Class2 = class extends Obj.Class1 {};
        new obj.Class2()""".stripMargin.trim,
      expected = """const obj = { Class1: class { static foo = "constant" } };
        obj.Class2 = class extends Obj.Class1 {};
        new obj.Class2()""".stripMargin.trim,
      options = AllOff.copy(
        collapseVars = true,
        joinVars = true,
        properties = true,
        reduceVars = true,
        sideEffects = true,
        unused = true
      )
    )
  }

  // =========================================================================
  // static_means_execution
  // =========================================================================
  test("static_means_execution".fail) {
    assertCompresses(
      input = """let x = 0;
        class NoProps { }
        class WithProps {
            prop = (x = x === 1 ? "PASS" : "FAIL")
        }
        class WithStaticProps {
            static prop = (x = x === 0 ? 1 : "FAIL")
        }

        new NoProps();
        new WithProps();
        new WithStaticProps();

        console.log(x)""".stripMargin.trim,
      expected = """let x = 0;
        // Does not get inlined as it contains an immediate side effect
        class WithStaticProps {
            static prop = (x = x === 0 ? 1 : "FAIL")
        }
        new class {};
        new class {
            prop = (x = x === 1 ? "PASS" : "FAIL")
        };
        new WithStaticProps();

        console.log(x)""".stripMargin.trim,
      options = AllOff.copy(
        reduceVars = true,
        toplevel = ToplevelConfig(funcs = true, vars = true),
        unused = true
      )
    )
  }

  // =========================================================================
  // mangle_class_properties
  // =========================================================================
  test("mangle_class_properties".fail) {
    assertCompresses(
      input = """class Foo {
            bar = "bar";
            static zzz = "zzz"
            toString() {
                return this.bar + Foo.zzz;
            }
        }""".stripMargin.trim,
      expected = """class Foo {
            t = "bar";
            static o = "zzz"
            toString() {
                return this.t + Foo.o;
            }
        }""".stripMargin.trim,
      options = AllOff
    )
  }

