  test("mangle_class_properties_keep_quoted".fail) {
    assertCompresses(
      input = """class Foo {
            "bar" = "bar";
            static "zzz" = "zzz"
            toString() {
                return this.bar + Foo.zzz;
            }
        }""".stripMargin.trim,
      expected = """class Foo {
            "bar" = "bar";
            static "zzz" = "zzz"
            toString() {
                return this.bar + Foo.zzz;
            }
        }""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
