  // =========================================================================
  test("private_class_properties".fail) {
    assertCompresses(
      input = """class Foo {
            #bar = "FooBar"

            get bar() {
                return this.#bar;
            }
        }
        console.log(new Foo().bar)""".stripMargin.trim,
      expected = """class Foo {
            #bar = "FooBar"

            get bar() {
                return this.#bar;
            }
        }
        console.log(new Foo().bar)""".stripMargin.trim,
      options = AllOff.copy(
