      )
    )
  }

  // =========================================================================
  // optional_chaining_private_fields
  // =========================================================================
  test("optional_chaining_private_fields".fail) {
    assertCompresses(
      input = """class A {
            #opt = undefined;
            toString() {
                return this?.#opt ?? "PASS";
            }
        }
        console.log(new A().toString())""".stripMargin.trim,
