    assertCompresses(
      input = """class A {
            #p;
            isA (input) {
                #p in input; 
                #p in this;
                return #p in this; 
            }
        }""".stripMargin.trim,
      expected = "class A{#i;i(i){#i in i;#i in this;return #i in this}}",
